const grouped = {};

for (const item of items) {
  const row = item.json;
  const email = row.project_manager_email;

  if (!email) continue;

  if (!grouped[email]) {
    grouped[email] = {
      project_manager_email: email,
      project_manager_firstname: row.project_manager_firstname || '',
      project_manager_lastname: row.project_manager_lastname || '',
      project_manager_name: `${row.project_manager_firstname || ''} ${row.project_manager_lastname || ''}`.trim(),
      issues: []
    };
  }

  grouped[email].issues.push({
    issue_id: row.issue_id,
    issue_title: row.issue_title || 'N/A',

    description: row.description || 'N/A',
    priority: row.priority || 'N/A',
    status: row.status || 'N/A',
    created_at: row.created_at || 'N/A',

    issue_end_date_ist: row.issue_end_date_ist || 'N/A',
    overdue_days: row.overdue_days ?? 0,

    project_id: row.project_id,
    project_title: row.project_title || 'N/A',

    milestone_id: row.milestone_id,
    milestone_title: row.milestone_title || 'N/A',

    task_id: row.task_id,
    task_title: row.task_title || 'N/A',

    responsible_person_id: row.responsible_person_id,
    responsible_person_firstname: row.responsible_person_firstname || '',
    responsible_person_lastname: row.responsible_person_lastname || '',
    responsible_person_name: `${row.responsible_person_firstname || ''} ${row.responsible_person_lastname || ''}`.trim() || 'N/A',
    responsible_person_email: row.responsible_person_email || 'N/A'
  });
}

// optional: sort issues by highest overdue first
Object.values(grouped).forEach(pm => {
  pm.issues.sort((a, b) => b.overdue_days - a.overdue_days);
});

return Object.values(grouped).map(pm => ({
  json: {
    project_manager_email: pm.project_manager_email,
    project_manager_firstname: pm.project_manager_firstname,
    project_manager_lastname: pm.project_manager_lastname,
    project_manager_name: pm.project_manager_name,
    total_overdue_issues: pm.issues.length,
    issues: pm.issues
  }
}));

